def drop_cap(s):
    result = []
    i = 0
    n = len(s)
    while i < n:
        if s[i].isspace():
            result.append(s[i])
            i += 1
        else:
            start = i
            while i < n and not s[i].isspace():
                i += 1
            word = s[start:i]
            word_len = len(word)
            if word_len > 2:
                first = word[0].upper()
                rest = ''.join(c.lower() for c in word[1:])
                result.append(first + rest)
            else:
                result.append(word)
    return ''.join(result)

