def getAllPrimeFactors(n):
    if n <= 0:
        return []
    if n == 1:
        return [1]
    factors = []
    while n % 2 == 0:
        factors.append(2)
        n //= 2
    i = 3
    while i * i <= n:
        while n % i == 0:
            factors.append(i)
            n //= i
        i += 2
    if n > 1:
        factors.append(n)
    return factors

def getUniquePrimeFactorsWithCount(n):
    if n <= 0:
        return [[], []]
    if n == 1:
        return [[1], [1]]
    primes = []
    counts = []
    temp_n = n
    count = 0
    while temp_n % 2 == 0:
        count += 1
        temp_n //= 2
    if count > 0:
        primes.append(2)
        counts.append(count)
    i = 3
    while i * i <= temp_n:
        count = 0
        while temp_n % i == 0:
            count += 1
            temp_n //= i
        if count > 0:
            primes.append(i)
            counts.append(count)
        i += 2
    if temp_n > 1:
        primes.append(temp_n)
        counts.append(1)
    return [primes, counts]

def getUniquePrimeFactorsWithProducts(n):
    if n <= 0:
        return []
    if n == 1:
        return [1]
    prods = []
    temp_n = n
    count = 0
    while temp_n % 2 == 0:
        count += 1
        temp_n //= 2
    if count > 0:
        prods.append(2 ** count)
    i = 3
    while i * i <= temp_n:
        count = 0
        while temp_n % i == 0:
            count += 1
            temp_n //= i
        if count > 0:
            prods.append(i ** count)
        i += 2
    if temp_n > 1:
        prods.append(temp_n)
    return prods

