class UF:
    def __init__(self, n):
        self.p = list(range(n))
        self.rank = [0] * n

    def union(self, x, y):
        px = self.find(x)
        py = self.find(y)
        if px == py:
            return
        if self.rank[px] < self.rank[py]:
            self.p[px] = py
        elif self.rank[px] > self.rank[py]:
            self.p[py] = px
        else:
            self.p[py] = px
            self.rank[px] += 1

    def find(self, x):
        if self.p[x] != x:
            self.p[x] = self.find(self.p[x])
        return self.p[x]

